1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	};
6	
7	export function processScenario(scenario: any): any {
8	  const step = scenario.steps[0];
9	  let basePremium = 0;
10	  for (const item of step.items) {
11	    basePremium += BASE_PREMIUMS[item.type] ?? 0;
12	  }
13	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
14	}
